+type Heading = {level: number, text: string, anchor: string};
+
+const tocStart = /^\\s*<!--\\s*toc\\s*-->\\s*$/i;
+const tocEnd = /^\\s*<!--\\s*\\/toc\\s*-->\\s*$/i;
+const atxHeading = /^(?: {0,3})(#{1,6})[ \	]+(.*)$/;
+
+@RuleBuilder.register
+export default class AutoToc extends RuleBuilder<AutoTocOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.auto-toc.name',
+      descriptionKey: 'rules.auto-toc.description',
+      type: RuleType.CONTENT,
+    });
+  }
+
+  get OptionsClass(): new () => AutoTocOptions {
+    return AutoTocOptions;
+  }
+
+  apply(text: string, options: AutoTocOptions): string {
+    const lines = text.split('\
');
+    const startIndex = lines.findIndex((line) => tocStart.test(line));
+    if (startIndex === -1) {
+      return text;
+    }
+
+    const endOffset = lines.slice(startIndex + 1).findIndex((line) => tocEnd.test(line));
+    const endIndex = endOffset === -1 ? -1 : startIndex + 1 + endOffset;
+    const headings = this.getHeadings(lines, startIndex, endIndex, options);
+    const toc = this.buildToc(lines[startIndex], headings, options);
+    const replaceEnd = endIndex === -1 ? startIndex : endIndex;
+    lines.splice(startIndex, replaceEnd - startIndex + 1, ...toc);
+    return lines.join('\
');
+  }
+
+  private getHeadings(lines: string[], tocStartIndex: number, tocEndIndex: number, options: AutoTocOptions): Heading[] {
+    const headings: Heading[] = [];
+    const anchors = new Map<string, number>();
+    let inYaml = false;
+    let inFence: string = null;
+    let inMath = false;
+
+    for (let index = 0; index < lines.length; index++) {
+      const line = lines[index];
+      if (index === 0 && /^---\\s*$/.test(line)) {
+        inYaml = true;
+        continue;
+      }
+      if (inYaml) {
+        if (/^(---|\\.\\.\\.)\\s*$/.test(line)) inYaml = false;
+        continue;
+      }
+
+      const fence = line.match(/^ {0,3}(`{3,}|~{3,})/);
+      if (fence) {
+        if (inFence === null) inFence = fence[1][0];
+        else if (inFence === fence[1][0]) inFence = null;
+        continue;
+      }
+      if (inFence !== null) continue;
+
+      if (/^\\s*\\$\\$/.test(line) || /^\\s*\\\\\\[\\s*$/.test(line) || /^\\s*\\\\\\]\\s*$/.test(line)) {
+        inMath = !inMath;
+        continue;
+      }
+      if (inMath || (index > tocStartIndex && (tocEndIndex === -1 || index < tocEndIndex))) continue;
+
+      const match = line.match(atxHeading);
+      if (!match) continue;
+      const level = match[1].length;
+      if (level < options.minLevel || level > options.maxLevel) continue;
+
+      const parsed = parseHeadingText(match[2], options.useExplicitIds);
+      if (isExcluded(parsed.text, options.excludeHeadings)) continue;
+      const baseAnchor = parsed.explicitId ?? makeAnchor(parsed.text);
+      const duplicateNumber = anchors.get(baseAnchor) ?? 0;
+      anchors.set(baseAnchor, duplicateNumber + 1);
+      headings.push({
+        level,
+        text: options.stripFormattingInToc ? stripFormatting(parsed.text) : parsed.text,
+        anchor: duplicateNumber === 0 ? baseAnchor : `${baseAnchor}-${duplicateNumber}`,
+      });
+    }
+    return headings;
+  }
+
+  private buildToc(startMarker: string, headings: Heading[], options: AutoTocOptions): string[] {
+    const result = [startMarker, ''];
+    if (options.title) result.push(options.title, '');
+    headings.forEach((heading, index) => {
+      const indentation = ' '.repeat(Math.max(0, heading.level - options.minLevel) * options.indentSize);
+      const marker = options.listStyle === 'number' ? `${options.orderedListStyle === 'increment' ? index + 1 : 1}.` : options.bulletMarker;
+      result.push(`${indentation}${marker} [${heading.text}](#${heading.anchor})`);
+    });
+    result.push('', '<!-- /toc -->', '');
+    return result;
+  }
+
+  get exampleBuilders(): ExampleBuilder<AutoTocOptions>[] {
+    return [new ExampleBuilder({
+      description: 'Creates a table of contents from headings when the TOC marker is present.',
+      before: '<!-- toc -->\
\
## First\
\
### Second',
+      after: '<!-- toc -->\
\
- [First](#first)\
  - [Second](#second)\
\
<!-- /toc -->\
\
## First\
\
### Second',
+    })];
+  }
+
+  get optionBuilders(): OptionBuilderBase<AutoTocOptions>[] {
+    return [];
+  }
+}
+
+function parseHeadingText(text: string, useExplicitIds: boolean): {text: string, explicitId?: string} {
+  let result = text.replace(/[ \	]+#+\\s*$/, '').trim();
+  const explicitId = result.match(/\\s*\\{#([^{}\\s]+)\\}\\s*$/);
+  if (explicitId) result = result.slice(0, explicitId.index).trim();
+  return {text: result, explicitId: useExplicitIds && explicitId ? explicitId[1] : undefined};
+}
+
+function isExcluded(text: string, excludedHeadings: string[]): boolean {
+  const value = stripFormatting(text).trim();
+  return excludedHeadings.some((excluded) => {
+    const trimmed = excluded.trim();
+    if (trimmed.startsWith('/') && trimmed.lastIndexOf('/') > 0) {
+      try {
+        return new RegExp(trimmed.slice(1, trimmed.lastIndexOf('/')), 'i').test(value);
+      } catch (_) {
+        return value.toLowerCase() === trimmed.toLowerCase();
+      }
+    }
+    return value.toLowerCase() === trimmed.toLowerCase();
+  });
+}
+
+function makeAnchor(text: string): string {
+  return stripFormatting(text)
+      .toLowerCase()
+      .replace(/\\s+/g, '-')
+      .replace(/[^a-z0-9_-]/g, '')
+      .replace(/-+/g, '-')
+      .replace(/^-+|-+$/g, '');
+}
+
+function stripFormatting(text: string): string {
+  return text
+      .replace(/!\\[\\[[^\\]]*\\]\\]/g, '')
+      .replace(/!\\[[^\\]]*\\]\\([^)]*\\)/g, '')
+      .replace(/\\[\\[([^\\]|]+)(?:\\|([^\\]]+))?\\]\\]/g, (_, target: string, display: string) => display ?? target)
+      .replace(/\\[([^\\]]*)\\]\\([^)]*\\)/g, '$1')
+      .replace(/[`*_~]/g, '')
+      .replace(/<[^>]*>/g, '');
